-- Migration 005: Align local migrations with production schema.
--
-- Generated by `supabase db diff --linked` on 2026-05-02 to capture ~23 tables,
-- 12 functions, 78 indexes, 7 policies, 3 triggers, and many constraints that
-- had accumulated in production via the Supabase Studio UI without ever being
-- captured in a migration file. This migration brings the sequential `001`-`005`
-- chain back in sync with what production actually looks like, so a fresh
-- `supabase db push` against an empty project reproduces production end-to-end.
--
-- This file is idempotent for the trivial cases (CREATE TABLE / INDEX / TRIGGER /
-- POLICY all guarded by IF NOT EXISTS or DROP IF EXISTS). The 96 `add constraint`
-- statements are NOT idempotent — they will fail if reapplied to a database
-- where the constraints already exist. To prevent this on the existing
-- production database (where everything already exists), this migration must be
-- marked as already applied via:
--
--   npx supabase migration repair --status applied 005
--
-- After repair, `db push` skips this migration on production while still
-- replaying it on fresh environments.

drop extension if exists "pg_net";

drop index if exists "public"."idx_usage_events_ai_query";


