set check_function_bodies = off;

CREATE OR REPLACE FUNCTION public.check_plan_limits(p_user_id uuid, p_resource text)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_plan TEXT;
  v_tracked_count INTEGER;
  v_limit INTEGER;
BEGIN
  SELECT plan, tracked_count INTO v_plan, v_tracked_count
  FROM user_profiles
  WHERE id = p_user_id;

  IF p_resource = 'products' THEN
    CASE v_plan
      WHEN 'free' THEN v_limit := 5;
      WHEN 'pro' THEN v_limit := 999;
      WHEN 'ultra' THEN v_limit := 999;
      WHEN 'mega' THEN v_limit := 999;
      ELSE v_limit := 5;
    END CASE;
    
    RETURN v_tracked_count < v_limit;
  END IF;

  RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_scenario_limit(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_tier TEXT;
  v_limit INTEGER;
  v_used INTEGER;
BEGIN
  SELECT subscription_tier, monthly_scenario_limit, scenarios_used_this_month
  INTO v_tier, v_limit, v_used
  FROM user_profiles
  WHERE user_id = p_user_id;
  IF v_tier = 'starter' THEN
    RETURN FALSE;
  ELSIF v_tier = 'pro' THEN
    RETURN COALESCE(v_used, 0) < COALESCE(v_limit, 3);
  ELSIF v_tier = 'business' THEN
    RETURN TRUE;
  ELSE
    RETURN FALSE;
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_tier(p_user_id uuid)
 RETURNS text
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  SELECT subscription_tier 
  FROM user_profiles 
  WHERE user_id = p_user_id;
$function$
;

CREATE OR REPLACE FUNCTION public.has_feature_access(p_user_id uuid, p_feature text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_tier TEXT;
BEGIN
  SELECT subscription_tier INTO v_tier
  FROM user_profiles
  WHERE user_id = p_user_id;
  IF v_tier = 'starter' THEN
    RETURN p_feature IN ('dashboard', 'metrics', 'stripe_connection');
  ELSIF v_tier = 'pro' THEN
    RETURN p_feature IN (
      'dashboard', 'metrics', 'stripe_connection',
      'churn_prevention', 'peer_benchmarking', 'scenarios_limited'
    );
  ELSIF v_tier = 'business' THEN
    RETURN TRUE;
  ELSE
    RETURN FALSE;
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.increment_scenario_usage(p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE user_profiles
  SET scenarios_used_this_month = COALESCE(scenarios_used_this_month, 0) + 1
  WHERE user_id = p_user_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reset_monthly_scenario_usage()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE user_profiles
  SET scenarios_used_this_month = 0
  WHERE subscription_tier = 'pro';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reset_monthly_usage()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE user_profiles
  SET api_calls_this_month = 0
  WHERE EXTRACT(DAY FROM NOW()) = 1; -- Reset on the 1st of each month
END;
$function$
;

CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.track_api_usage(p_user_id uuid, p_endpoint text, p_method text, p_status_code integer, p_response_time_ms integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Insert usage record
  INSERT INTO api_usage (
    user_id, endpoint, method, status_code, response_time_ms
  ) VALUES (
    p_user_id, p_endpoint, p_method, p_status_code, p_response_time_ms
  );

  -- Update monthly counter
  UPDATE user_profiles
  SET 
    api_calls_this_month = api_calls_this_month + 1,
    last_api_call = NOW()
  WHERE id = p_user_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_churn_prediction_timestamp()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_updated_at_column()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_updated_at_saas()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = TIMEZONE('utc', NOW());
  RETURN NEW;
END;
$function$
;

create or replace view "public"."view_connection_metrics" as  SELECT stripe_connection_id,
    count(DISTINCT customer_id) AS total_customers,
    count(*) FILTER (WHERE (status = ANY (ARRAY['active'::text, 'trialing'::text]))) AS active_subscriptions,
    COALESCE(sum(mrr_amount) FILTER (WHERE (status = ANY (ARRAY['active'::text, 'trialing'::text]))), (0)::numeric) AS mrr
   FROM public.subscriptions_cache
  GROUP BY stripe_connection_id;


