drop policy if exists "leak_action_state_select_own" on "public"."leak_action_state";
  create policy "leak_action_state_select_own"
  on "public"."leak_action_state"
  as permissive
  for select
  to public
using ((auth.uid() = user_id));



drop policy if exists "leak_action_state_upsert_own" on "public"."leak_action_state";
  create policy "leak_action_state_upsert_own"
  on "public"."leak_action_state"
  as permissive
  for all
  to public
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));



